   242→	@LogExecution()
   243→	async getTask({ taskId }: { taskId: string }): Promise<{
   244→		state: string;
   245→		model_id?: string;
   246→	}> {
   247→		try {
   248→			const response = await this.client.transport.request({
   249→				method: 'GET',
   250→				path: `/_plugins/_ml/tasks/${taskId}`,
   251→			});
   252→
   253→			const body = response.body as { state: string; model_id?: string };
   254→			return {
   255→				state: body.state,
   256→				...(body.model_id !== undefined && { model_id: body.model_id }),
   257→			};
   258→		} catch (error: unknown) {
   259→			this.handleError({ context: `Failed to get task ${taskId}`, error });
   260→			throw error;
