   327→	private transformStyleToOpensearchProduct({
   328→		style,
   329→	}: {
   330→		style: IStylesMvBase;
   331→	}): IOpensearchProduct {
   332→		return {
   333→			_id: style._id,
   334→			style_id: style.style_id,
   335→			product_id: style.product_id,
   336→			name: style.name ?? '',
   337→			features: style.features,
   338→			general_comments: style.general_comments,
   339→			decoration_method: style.decoration_method,
   340→			manufacturer: style.manufacturer,
   341→			primary_category_id: style.primary_category_id,
   342→			primary_category_name: style.primary_category_name,
   343→			product_type: style.product_type,
   344→			style_type: style.style_type,
   345→			broad_category_names: style.broad_category_names,
   346→			sub_category_names: style.sub_category_names,
   347→			minimum_quantity: style.minimum_quantity,
   348→			min_qty: style.min_qty,
   349→			default_quote_qty: style.default_quote_qty,
   350→			sizes: style.sizes,
   351→			turn_time: style.turn_time,
   352→			rush_turn_time: style.rush_turn_time,
   353→			no_minimum: style.no_minimum ? 1 : 0,
   354→			price_level: style.price_level,
   355→			rating_score: style.rating_score !== null ? Number(style.rating_score) : null,
   356→			rating_count: style.rating_count,
   357→			default_unit_prices: style.default_unit_prices,
   358→			colors: style.colors,
   359→			style_card_image_url: style.style_card_image_url,
   360→			link: style.link,
   361→			brand: style.brand,
   362→			condensed_features: this.normalizeCondensedFeatures({
   363→				condensedFeatures: style.condensed_features,
   364→			}),
   365→			status: style.status,
   366→			created_at:
   367→				style.created_at instanceof Date
   368→					? style.created_at.toISOString()
   369→					: String(style.created_at),
   370→			updated_at:
   371→				style.updated_at instanceof Date
   372→					? style.updated_at.toISOString()
   373→					: String(style.updated_at),
   374→			deleted_at: style.deleted_at
   375→				? style.deleted_at instanceof Date
   376→					? style.deleted_at.toISOString()
   377→					: String(style.deleted_at)
   378→				: null,
   379→			combined_text_for_embedding:
   380→				style.embedding_text ?? this.buildCombinedTextForEmbedding({ style }),
   381→		};
   382→	}
   383→}
